"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[9965],{4761(e,o,t){t.r(o),t.d(o,{assets:()=>h,contentTitle:()=>i,default:()=>u,frontMatter:()=>r,metadata:()=>s,toc:()=>l});const s=JSON.parse('{"id":"stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-10","title":"Discourses \u2014 Book 2, Chapter 10","description":"Book 2 \u2014 Chapter 10","source":"@site/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-10.md","sourceDirName":"stoicism/epictetus/discourses/book-2","slug":"/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-10","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-10","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":11,"frontMatter":{"sidebar_position":11,"title":"Discourses \u2014 Book 2, Chapter 10","sidebar_label":"Book 2, Ch. 10"},"sidebar":"philosophersSidebar","previous":{"title":"Book 2, Ch. 9","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-9"},"next":{"title":"Book 2, Ch. 11","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-11"}}');var a=t(4848),n=t(8453);const r={sidebar_position:11,title:"Discourses \u2014 Book 2, Chapter 10",sidebar_label:"Book 2, Ch. 10"},i="Discourses",h={},l=[{value:"Book 2 \u2014 Chapter 10",id:"book-2--chapter-10",level:2},{value:"How The Acts Appropriate To Man Are To Be Discovered From The Names He Bears",id:"how-the-acts-appropriate-to-man-are-to-be-discovered-from-the-names-he-bears",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function d(e){const o={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,n.R)(),...e.components},{Details:t}=o;return t||function(e,o){throw new Error("Expected "+(o?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,a.jsxs)(a.Fragment,{children:[(0,a.jsxs)("div",{style:{textAlign:"center"},children:[(0,a.jsx)(o.header,{children:(0,a.jsx)(o.h1,{id:"discourses",children:"Discourses"})}),(0,a.jsx)(o.h2,{id:"book-2--chapter-10",children:"Book 2 \u2014 Chapter 10"}),(0,a.jsx)(o.h3,{id:"how-the-acts-appropriate-to-man-are-to-be-discovered-from-the-names-he-bears",children:"How The Acts Appropriate To Man Are To Be Discovered From The Names He Bears"})]}),"\n",(0,a.jsx)(o.p,{children:(0,a.jsx)(o.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,a.jsxs)(t,{open:!0,children:[(0,a.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,a.jsx)(o.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,a.jsx)(o.p,{children:"A meditation on role and identity. Each name you bear \u2014 Man, Son, Brother, Councillor, Father \u2014 carries its own appropriate acts. Fulfilling those acts is what keeps you what you are; violating them is not a neutral choice but a self-destruction."}),(0,a.jsx)(o.p,{children:"The accounting of losses is the chapter's sharpest move. We readily count losses of property or physical function as real harm. But losing honor, trustworthiness, gentleness, self-control \u2014 we treat these as nothing, because no cash disappears. Epictetus reverses the valuation: the losses that come from outside the will (illness, poverty) are not dishonoring. The losses that come from our own choices \u2014 those are the only ones that actually diminish what you are. The man who harms another in retaliation harms himself; he's just too focused on whether the other person lost anything to notice."})]}),"\n",(0,a.jsxs)(t,{open:!0,children:[(0,a.jsx)("summary",{children:"Text"}),(0,a.jsx)(o.h2,{id:"text",children:"Text"}),(0,a.jsx)(o.p,{children:"CONSIDER who you are. First, a Man; that is, one who has nothing more sovereign than will, but all else subject to this, and will itself free from slavery or subjection. Consider then from what you are parted by reason. You are parted from wild beasts, you are parted from sheep. On these terms you are a citizen of the universe and a part of it, not one of those marked for service, but of those fitted for command; for you have the faculty to understand the divine governance of the universe and to reason on its sequence. What then is the calling of a Citizen? To have no personal interest, never to think about anything as though he were detached, but to be like the hand or the foot, which, if they had the power of reason and understood the order of nature, would direct every impulse and every process of the will by reference to the whole. That is why it is well said by philosophers that 'if the good man knew coming events beforehand he would help on nature, even if it meant working with disease, and death and maiming', for he would realize that by the ordering of the universe this task is allotted him, and that the whole is more commanding than the part and the city than the citizen. 'But seeing that we do not know beforehand, it is appropriate that we should hold fast to the things that are by nature more fit to be chosen; for indeed we are born for this.'"}),(0,a.jsx)(o.p,{children:"Next remember that you are a Son. What part do we expect a son to play? His part is to count all that is his as his father's, to obey him in"}),(0,a.jsx)(o.p,{children:"all things, never to speak ill of him to any, nor to say or do anything to harm him, to give way to him and yield him place in all things, working with him so far as his powers allow."}),(0,a.jsx)(o.p,{children:"Next know that you are also a Brother. For this part too you are bound to show a spirit of concession and obedience; and to speak kindly, and not to claim against another anything that is outside the will, but gladly to sacrifice those things, that you may gain in the region where your will has control. For look what a thing it is to gain good nature at the price of a lettuce, if it so chance, or the surrender of a chair: what a gain is that!"}),(0,a.jsx)(o.p,{children:"Next, if you are a member of a city council, remember that you are a councillor; if young, that you are young; if old, that you are old; if a father, that you are a father. For each of these names, if properly considered, suggests the acts appropriate to it. But if you go and disparage your brother, I tell you that you are forgetting who you are and what is your name. I say, if you were a smith and used your hammer wrong, you would have forgotten the smith; but if you forget the brother's part and turn into an enemy instead of a brother, are you going to imagine that you have undergone no change? If instead of man, a gentle and sociable creature, you have become a dangerous, aggressive, and biting brute, have you lost nothing? Do you think you must lose cash in order to suffer damage? Does no other sort of loss damage man? If you lost skill in grammar or music you would count the loss as damage; if you are going to lose honour and dignity and gentleness, do you count it as nothing? Surely those other losses are due to some external cause outside our will, but these are due to ourselves. Those qualities it is no honour to have and no dishonour to lose, but these you cannot lack or lose without dishonour, reproach, and disaster."}),(0,a.jsx)(o.p,{children:"What does he lose who is the victim of unnatural lust? He loses his manhood. And the agent of such lust, what does he lose? He loses his manhood like the other, and much besides. What does the adulterer lose? He loses the man of honour and self-control, the gentleman, the citizen, the neighbour. What does the angry man lose? Something else. The man who fears? Something else. No one is evil without destruction and loss."}),(0,a.jsx)(o.p,{children:"If on the other hand you look for loss in paltry pence, all the men I have mentioned are without loss or damage, if it so chance, nay they actually receive gain and profit, when they get cash by any of these actions. But notice, that if you make money the standard in everything, you will not count even the man who loses his nose as having suffered injury."}),(0,a.jsx)(o.p,{children:"'Yes, I do,' he says, 'for his body is mutilated.'"}),(0,a.jsx)(o.p,{children:"Well, but does the man who has lost, not his nose but his sense of"}),(0,a.jsx)(o.p,{children:"smell, lose nothing? Is there no faculty of the mind, which brings gain to him that gets it and hurt to him that loses it?"}),(0,a.jsx)(o.p,{children:"'What can possibly be the faculty you mean?'"}),(0,a.jsx)(o.p,{children:"Have we no natural sense of honour?"}),(0,a.jsx)(o.p,{children:"'We have.'"}),(0,a.jsx)(o.p,{children:"Does he that destroys this suffer no damage, no deprivation, no loss of what belongs to him? Have we not a natural faculty of trust, a natural gift of affection, of beneficence, of mutual toleration? Are we then to count the man who suffers himself to be injured in regard to these as free from loss and damage?"}),(0,a.jsx)(o.p,{children:"'What conclusion do you draw? Am I not to harm him who harmed me?'"}),(0,a.jsx)(o.p,{children:"First consider what 'harm' means and remember what you heard from the philosophers. For if good lies in the will and evil also lies in the will, look whether what you are saying does not come to this: 'What do you mean? As he harmed himself by doing me a wrong, am I not to harm myself by doing him a wrong?' Why then do we not look at things in this light? When we suffer some loss in body or property, we count it hurt: is there no hurt, when we suffer loss in respect of our will?"}),(0,a.jsx)(o.p,{children:"Of course the man who is deceived or the man who does a wrong has no pain in his head or his eye or his hip, nor does he lose his estate; and these are the things we care for, nothing else. But we take no concern whatever whether our will is going to be kept honourable and trustworthy or shameless and faithless, except only so far as we discuss it in the lecture-room, and therefore so far as our wretched discussions go we make some progress, but beyond them not the least."})]})]})}function u(e={}){const{wrapper:o}={...(0,n.R)(),...e.components};return o?(0,a.jsx)(o,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},8453(e,o,t){t.d(o,{R:()=>r,x:()=>i});var s=t(6540);const a={},n=s.createContext(a);function r(e){const o=s.useContext(n);return s.useMemo(function(){return"function"==typeof e?e(o):{...o,...e}},[o,e])}function i(e){let o;return o=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:r(e.components),s.createElement(n.Provider,{value:o},e.children)}}}]);